{"content": "     1|import { MetadataRoute } from 'next'
     2|import { readFileSync } from 'fs'
     3|import { join } from 'path'
     4|
     5|const BASE = 'https://nexa.paragu-ai.com'
     6|const LOCALES = ['es', 'en', 'nl', 'de']
     7|
     8|function getPages(): string[] {
     9|  try {
    10|    const dir = join(process.cwd(), 'nexa-pages')
    11|    return require('fs').readdirSync(dir).filter((f: string) => f.endsWith('.json')).map((f: string) => f.replace('.json', ''))
    12|  } catch { return ['programas', 'nosotros', 'contacto', 'faq', 'glosario'] }
    13|}
    14|
    15|export default function sitemap(): MetadataRoute.Sitemap {
    16|  const pages = ['home', ...getPages().filter(p => p !== 'home')]
    17|  const entries: MetadataRoute.Sitemap = []
    18|  for (const locale of LOCALES) {
    19|    for (const page of pages) {
    20|      const url = `${BASE}/${locale}/${page === 'home' ? '' : page}`
    21|      entries.push({
    22|        url: url.replace(/\/$/, ''),
    23|        lastModified: new Date(),
    24|        changeFrequency: 'monthly' as const,
    25|        priority: page === 'home' ? 1 : 0.8,
    26|        alternates: { languages: Object.fromEntries(LOCALES.map(l => [l, `${BASE}/${l}/${page === 'home' ? '' : page}`.replace(/\/$/, '')])) },
    27|      })
    28|    }
    29|  }
    30|  return entries
    31|}
